def safe_int_convert(value, default=None):
    try:
        return int(value)
    except (ValueError, TypeError):
        return default

# Using the function
result = safe_int_convert('123')  # returns 123
bad_result = safe_int_convert('abc', default=0)  # returns 0 instead of raising an error

print(result)     # Output: 123
print(bad_result) # Output: 0
